-- Test the trigger end-to-end. Wrapped in a DO block + rollback so no test data persists.
do $$
declare
  v_user_id uuid;
  v_link_id uuid;
  v_total int;
  v_latest int;
  v_latest_run text;
  v_followers int;
  v_avg_views int;
  v_verified boolean;
begin
  insert into public.users (role, username, email)
  values ('creator', 'us007_test', 'us007@example.com')
  returning id into v_user_id;

  insert into public.creator_profiles (user_id, display_name)
  values (v_user_id, 'US-007 Test');

  insert into public.social_links (user_id, platform, handle, status)
  values (v_user_id, 'tiktok', 'us007creator', 'active')
  returning id into v_link_id;

  -- First snapshot: fresh, fetched 1h ago.
  insert into public.metric_snapshots (
    social_link_id, scrape_mode, status,
    follower_count, avg_views_last_10, total_likes, video_count, is_verified,
    fetched_at, apify_run_id
  ) values (
    v_link_id, 'tiktok_profile', 'fresh',
    10000, 1500, 200000, 42, false,
    now() - interval '1 hour', 'run_aaa'
  );

  -- Second snapshot: fresh, now. Should claim is_latest, demote first.
  insert into public.metric_snapshots (
    social_link_id, scrape_mode, status,
    follower_count, avg_views_last_10, total_likes, video_count, is_verified,
    fetched_at, apify_run_id
  ) values (
    v_link_id, 'tiktok_profile', 'fresh',
    12500, 1800, 240000, 44, true,
    now(), 'run_bbb'
  );

  select count(*) into v_total
    from public.metric_snapshots where social_link_id = v_link_id;
  select count(*) into v_latest
    from public.metric_snapshots where social_link_id = v_link_id and is_latest;
  select apify_run_id into v_latest_run
    from public.metric_snapshots where social_link_id = v_link_id and is_latest;
  select tiktok_follower_count, tiktok_avg_views_last_10, tiktok_is_verified
    into v_followers, v_avg_views, v_verified
    from public.creator_profiles where user_id = v_user_id;

  raise notice 'total_snapshots=% latest_count=% latest_run=% denorm_followers=% denorm_avg_views=% denorm_verified=%',
    v_total, v_latest, v_latest_run, v_followers, v_avg_views, v_verified;

  -- Negative test: coherence trigger should reject ig_details on a tiktok link.
  begin
    insert into public.metric_snapshots (
      social_link_id, scrape_mode, status, fetched_at
    ) values (v_link_id, 'ig_details', 'fresh', now());
    raise exception 'coherence trigger FAILED to reject ig_details on tiktok link';
  exception when others then
    raise notice 'coherence trigger correctly rejected: %', sqlerrm;
  end;

  -- Negative test: refreshing rows must NOT denormalize and must NOT be_latest.
  insert into public.metric_snapshots (
    social_link_id, scrape_mode, status,
    follower_count, fetched_at, apify_run_id
  ) values (
    v_link_id, 'tiktok_profile', 'refreshing',
    99999, now() + interval '1 minute', 'run_ccc'
  );
  select tiktok_follower_count into v_followers
    from public.creator_profiles where user_id = v_user_id;
  raise notice 'after refreshing insert, denorm_followers=% (should still be 12500)', v_followers;

  raise exception 'rollback on purpose, test passed';
end $$;

